import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge, Tabs } from '../design-system/Badge/Badge';
import { Input } from '../design-system/Input/Input';
import '../theme/variables.css';

const AI = 'http://localhost:8000';

/* ========== UTILITY HOOKS ========== */

function useRecorder() {
  const [recording, setRecording] = useState(false);
  const mr = useRef<MediaRecorder|null>(null);
  const chunks = useRef<Blob[]>([]);
  const start = async () => {
    try { const s = await navigator.mediaDevices.getUserMedia({audio:true}); mr.current = new MediaRecorder(s,{mimeType:'audio/webm'}); chunks.current = []; mr.current.ondataavailable = e=>{if(e.data.size>0)chunks.current.push(e.data)}; mr.current.start(); setRecording(true); } catch(e) {}
  };
  const stop = (): Promise<Blob> => new Promise(resolve => {
    if (!mr.current) return;
    mr.current.onstop = () => { resolve(new Blob(chunks.current,{type:'audio/webm'})); mr.current?.stream.getTracks().forEach(t=>t.stop()); };
    mr.current.stop(); setRecording(false);
  });
  return { recording, start, stop };
}

async function transcribe(blob: Blob): Promise<string> {
  const fd = new FormData(); fd.append('file', blob, 'recording.webm');
  const r = await fetch(`${AI}/api/v1/scribe/transcribe`,{method:'POST',body:fd});
  return (await r.json()).text || '';
}

async function generateNote(transcript: string, patientCtx: any) {
  const r = await fetch(`${AI}/api/v1/scribe/generate`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({transcript,encounter_type:'visit',patient_context:patientCtx})});
  return r.json();
}

async function suggestBilling(diagnosis: string) {
  const r = await fetch(`${AI}/api/v1/billing/suggest`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({diagnosis,encounter_type:'visit'})});
  return r.json();
}

async function predictWorkflow(diagnosis: string, assessment: string) {
  const r = await fetch(`${AI}/api/v1/workflow/predict`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({diagnosis,assessment,patient_age:40})});
  return r.json();
}

/* ========== MAIN COMPONENT ========== */

function EncounterWorkspace() {
  const [transcript, setTranscript] = useState('');
  const [soap, setSoap] = useState<any>(null);
  const [billing, setBilling] = useState<any>(null);
  const [workflow, setWorkflow] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [tab, setTab] = useState('scribe');
  const [edited, setEdited] = useState<any>({});
  const { recording, start, stop } = useRecorder();

  const [patient, setPatient] = useState<any>(null);
  const [patientId, setPatientId] = useState('');
  const [vitals] = useState([{l:'BP',v:'128/82',u:'mmHg',t:'stable'},{l:'HR',v:'72',u:'bpm',t:'stable'},{l:'Temp',v:'37.0',u:'°C',t:'stable'},{l:'O2',v:'98',u:'%',t:'stable'}]);
  const [problems, setProblems] = useState<any[]>([]);
  const [meds, setMeds] = useState<any[]>([]);
  const [allergies, setAllergies] = useState<string[]>([]);

  useEffect(() => {
    const el = document.getElementById('encounter-root');
    const demoNo = el?.dataset.demoNo || '';
    setPatientId(demoNo);
    if (demoNo) {
      fetch(`${AI}/api/v1/patient/${demoNo}`).then(r=>r.json()).then(data=>{
        setPatient(data);
        setProblems(data.problems||[]);
        setMeds(data.medications||[]);
        setAllergies(data.allergies||[]);
      }).catch(()=>{});
    }
  }, []);

  const patientCtx = patient ? { name: patient.name, age: patient.dob ? new Date().getFullYear() - parseInt(patient.dob.substring(0,4)) : '', sex: patient.sex, problems: problems.map((p:any)=>p.name).join(', '), medications: meds.map((m:any)=>`${m.name}`).join(', '), allergies: allergies.join(', ') } : {};

  const displayDob = patient?.dob || '';
  const age = displayDob ? new Date().getFullYear() - parseInt(displayDob.substring(0,4)) : '';
  const allergiesCount = allergies.length;

  const handleRecord = async () => {
    if (recording) {
      setLoading(true); setError('');
      const blob = await stop();
      try { const text = await transcribe(blob); setTranscript(text); await processTranscript(text); }
      catch(e:any) { setError('Transcription failed: '+e.message); }
      finally { setLoading(false); }
    } else { start(); }
  };

  const processTranscript = async (text: string) => {
    try {
      const [s, b, w] = await Promise.all([generateNote(text, patientCtx), suggestBilling(problems.map(p=>p.n).join(', ')), predictWorkflow(problems.map(p=>p.n).join(', '), '')]);
      setSoap(s); setBilling(b); setWorkflow(w); setEdited({});
    } catch(e:any) { setError('AI processing failed: '+e.message); }
  };

  const handlePasteGenerate = async () => {
    if (!transcript) return;
    setLoading(true); setError('');
    try { await processTranscript(transcript); }
    catch(e:any) { setError(e.message); }
    finally { setLoading(false); }
  };

  const data = soap ? { ...soap, ...edited } : null;
  const trendIcons: any = { up:'↑', down:'↓', stable:'→' };
  const trendColors: any = { up:'#dc2626', down:'#16a34a', stable:'#a3a3a3' };

  return (
    <div style={{height:'100vh',display:'flex',flexDirection:'column',fontFamily:'-apple-system,BlinkMacSystemFont,sans-serif',background:'#f3f4f6'}}>
      {/* PATIENT HEADER */}
      <div style={{background:'linear-gradient(135deg,#1e3a8a,#2563eb)',color:'#fff',padding:'8px 20px',display:'flex',alignItems:'center',justifyContent:'space-between',boxShadow:'0 2px 8px rgba(0,0,0,0.15)',zIndex:100,minHeight:48}}>
        <div style={{display:'flex',alignItems:'center',gap:16}}>
          <h2 style={{fontSize:16,fontWeight:600,margin:0}}>OSCAR AI Encounter</h2>
          <div style={{fontSize:14,fontWeight:500}}>{patient?.name || 'Loading...'}</div>
          <span style={{fontSize:13,opacity:0.8}}>{displayDob && `DOB: ${displayDob}`} {age && `(${age}y)`} | {patient?.sex} | PHN: {patient?.hin}</span>
          {allergiesCount>0 && <Badge variant="error">{allergiesCount} allergies</Badge>}
        </div>
        <div style={{display:'flex',alignItems:'center',gap:12,fontSize:12}}>
          <a href={`/oscar/demographic/demographiccontrol.jsp?demographic_no=${patientId}&displaymode=edit&dboperation=search_detail`} target="_blank" style="color:rgba(255,255,255,0.85);text-decoration:none;">Edit Patient</a>
          <a href={`/oscar/oscarEncounter/IncomingEncounter.do?demographicNo=${patientId}`} target="_blank" style="color:rgba(255,255,255,0.85);text-decoration:none;padding:3px 8px;border:1px solid rgba(255,255,255,0.3);border-radius:4px;">Classic Encounter</a>
          <span style={{opacity:0.7}}>|</span>
          <a href="#" onClick={()=>window.open(`/oscar/oscarRx/choosePatient.do?demographicNo=${patientId}`,'Rx','width=700,height=1027')} style="color:rgba(255,255,255,0.85);text-decoration:none;">Rx</a>
          <a href="#" onClick={()=>window.open(`/oscar/dms/inboxManage.do?method=prepareForIndexPage&demographicNo=${patientId}`,'Labs','width=700,height=900')} style="color:rgba(255,255,255,0.85);text-decoration:none;">Labs</a>
          <a href="#" onClick={()=>window.open(`/oscar/oscarEncounter/IncomingEncounter.do?demographicNo=${patientId}`,'Forms','width=710,height=1024')} style="color:rgba(255,255,255,0.85);text-decoration:none;">Forms</a>
        </div>
      </div>

      {/* MAIN LAYOUT */}
      <div style={{display:'flex',flex:1,overflow:'hidden'}}>
        {/* LEFT SIDEBAR */}
        <div style={{width:240,background:'#fff',borderRight:'1px solid #e5e7eb',overflow:'auto',padding:'12px 0',boxShadow:'2px 0 8px rgba(0,0,0,0.04)'}}>
          <Card title="Vitals" style={{margin:'0 8px 8px'}}>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8}}>
              {vitals.map((v,i)=>(
                <div key={i} style={{textAlign:'center',padding:'8px 4px',background:'#f9fafb',borderRadius:6}}>
                  <div style={{fontSize:22,fontWeight:700,color:'#1f2937'}}>{v.v}</div>
                  <div style={{fontSize:11,color:'#6b7280'}}>
                    {v.l} {v.u}
                    <span style={{color:trendColors[v.t],marginLeft:2}}>{trendIcons[v.t]}</span>
                  </div>
                </div>
              ))}
            </div>
          </Card>

          <Card title="Active Problems" style={{margin:'0 8px 8px'}}>
            {problems.length > 0 ? problems.map((p:any,i:number)=>(
              <div key={i} style={{display:'flex',justifyContent:'space-between',padding:'4px 0',fontSize:13,borderBottom:'1px solid #f3f4f6'}}>
                <span>{p.name}</span>
                <span style={{fontSize:11,color:'#6b7280',fontFamily:'monospace'}}>{p.code}</span>
              </div>
            )) : <div style={{fontSize:12,color:'#9ca3af',textAlign:'center',padding:8}}>No active problems</div>}
            <a href={`/oscar/demographic/demographiccontrol.jsp?demographic_no=${patientId}&displaymode=edit`} target="_blank" style={{fontSize:11,color:'#2563eb',display:'block',textAlign:'center',marginTop:6,textDecoration:'none'}}>Edit in Oscar →</a>
          </Card>

          <Card title="Medications" style={{margin:'0 8px 8px'}}>
            {meds.length > 0 ? meds.map((m:any,i:number)=>(
              <div key={i} style={{fontSize:13,padding:'4px 0',borderBottom:'1px solid #f3f4f6'}}>
                <strong>{m.name}</strong> <span style={{color:'#6b7280'}}>{m.frequency || ''}</span>
              </div>
            )) : <div style={{fontSize:12,color:'#9ca3af',textAlign:'center',padding:8}}>No medications</div>}
            <a href="#" onClick={()=>window.open(`/oscar/oscarRx/choosePatient.do?demographicNo=${patientId}`,'Rx','width=700,height=1027')} style={{fontSize:11,color:'#2563eb',display:'block',textAlign:'center',marginTop:6,textDecoration:'none'}}>Prescribe in Oscar →</a>
          </Card>

          <Card title="Allergies" style={{margin:'0 8px 8px'}}>
            <div style={{display:'flex',gap:4,flexWrap:'wrap'}}>
              {allergies.length > 0 ? allergies.map((a:any,i:number)=><Badge key={i} variant="warning">{typeof a === 'string' ? a : a.name}</Badge>) : <span style={{fontSize:12,color:'#9ca3af'}}>None recorded</span>}
            </div>
          </Card>

          <div style={{padding:'8px 16px',marginTop:8,borderTop:'1px solid #e5e7eb'}}>
            <div style={{fontSize:11,color:'#6b7280',marginBottom:4}}>Clinical editing (problems, meds, allergies, forms, labs, referrals) uses Oscar's existing pages until each module gets its React replacement.</div>
          </div>
        </div>

        {/* MAIN WORKSPACE */}
        <div style={{flex:1,display:'flex',flexDirection:'column',overflow:'hidden'}}>
          {/* SCRIBE TOOLBAR */}
          <div style={{background:'#fff',borderBottom:'1px solid #e5e7eb',padding:'10px 16px',display:'flex',alignItems:'center',gap:12,flexWrap:'wrap'}}>
            <Button onClick={handleRecord} variant={recording?'danger':'primary'} size="sm" disabled={loading}>
              {recording ? <>
                <span style={{display:'inline-block',width:8,height:8,borderRadius:'50%',background:'#fff',marginRight:6,animation:'pulse 1s infinite'}} />Stop Recording
              </> : loading ? 'Processing...' : 'Start Recording'}
            </Button>
            <Input value={transcript} onChange={e=>setTranscript(e.target.value)} placeholder="Or paste transcript and generate..." style={{flex:1}} />
            <Button onClick={handlePasteGenerate} disabled={!transcript||loading} variant="secondary" size="sm">Generate</Button>
            {error && <span style={{color:'#dc2626',fontSize:13}}>{error}</span>}
          </div>

          {/* CONTENT AREA */}
          <div style={{flex:1,overflow:'auto',padding:16}}>
            {!data && !loading && transcript && (
              <Card title="Transcript">
                <div style={{whiteSpace:'pre-wrap',fontSize:14,lineHeight:1.6,color:'#374151'}}>{transcript}</div>
              </Card>
            )}
            {!data && !loading && !transcript && (
              <div style={{textAlign:'center',padding:60,color:'#9ca3af'}}>
                <div style={{fontSize:48,marginBottom:16}}>🎙️</div>
                <div style={{fontSize:18,fontWeight:500,marginBottom:8}}>Start an Encounter</div>
                <div style={{fontSize:14}}>Click "Start Recording" to begin the AI scribe, or paste a transcript.</div>
              </div>
            )}
            {loading && (
              <div style={{textAlign:'center',padding:60,color:'#6b7280'}}>
                <div style={{fontSize:24,fontWeight:500,marginBottom:8}}>{recording ? 'Recording...' : 'Processing...'}</div>
                <div style={{width:40,height:40,border:'3px solid #e5e7eb',borderTopColor:'#2563eb',borderRadius:'50%',margin:'0 auto',animation:'spin 0.8s linear infinite'}} />
              </div>
            )}

            {data && (
              <div>
                <Tabs tabs={[
                  {key:'soap',label:'SOAP Note'},
                  {key:'billing',label:`Billing (${billing?.suggestions?.length||0})`},
                  {key:'workflow',label:'Actions'},
                ]} activeKey={tab} onChange={setTab} />

                <div style={{marginTop:16}}>
                  {tab==='soap' && (
                    <div style={{display:'flex',flexDirection:'column',gap:12}}>
                      <EditableSec label="Subjective" value={data.subjective} onChange={v=>setEdited((p:any)=>({...p,subjective:v}))} />
                      <EditableSec label="Objective" value={data.objective} onChange={v=>setEdited((p:any)=>({...p,objective:v}))} />
                      <EditableSec label="Assessment" value={data.assessment} onChange={v=>setEdited((p:any)=>({...p,assessment:v}))} />
                      <EditableSec label="Plan" value={data.plan} onChange={v=>setEdited((p:any)=>({...p,plan:v}))} />
                      {data.follow_up && (
                        <div style={{padding:12,background:'#eff6ff',borderRadius:8,fontSize:13,color:'#1e40af'}}>
                          <strong>Follow-up:</strong> {data.follow_up}
                          {data.referral_needed && <span style={{marginLeft:12,color:'#d97706'}}>Refer: {data.referral_specialty} ({data.referral_urgency})</span>}
                        </div>
                      )}
                      <details>
                        <summary style={{cursor:'pointer',fontSize:13,color:'#6b7280'}}>View Transcript</summary>
                        <div style={{padding:12,background:'#f9fafb',borderRadius:6,fontSize:13,whiteSpace:'pre-wrap',marginTop:8,lineHeight:1.5}}>{transcript}</div>
                      </details>
                    </div>
                  )}

                  {tab==='billing' && billing?.suggestions?.map((b:any,i:number)=>(
                    <div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:10,borderBottom:'1px solid #f3f4f6'}}>
                      <div>
                        <strong style={{fontSize:16}}>{b.code}</strong> <span style={{color:'#6b7280',fontSize:14}}>{b.description}</span>
                        <div style={{fontSize:12,color:'#9ca3af'}}>{b.rationale}</div>
                      </div>
                      <div style={{textAlign:'right'}}>
                        <strong style={{fontSize:16,color:'#2563eb'}}>${b.fee?.toFixed(2)}</strong>
                        <div><Badge variant={b.confidence>=0.85?'success':'warning'}>{Math.round(b.confidence*100)}%</Badge></div>
                      </div>
                    </div>
                  ))}
                  {tab==='billing' && !billing?.suggestions?.length && <p style={{color:'#9ca3af',textAlign:'center',padding:20}}>No billing suggestions</p>}

                  {tab==='workflow' && workflow && (
                    <div style={{display:'flex',flexDirection:'column',gap:16}}>
                      {workflow.prescriptions?.length>0 && <Card title="Prescriptions">
                        {workflow.prescriptions.map((p:any,i:number)=>(
                          <div key={i} style={{padding:8,borderBottom:'1px solid #f3f4f6'}}>
                            <strong>{p.drug} {p.dose}</strong> — {p.route} {p.frequency} x {p.duration}
                            <div style={{fontSize:12,color:'#6b7280'}}>{p.rationale}</div>
                          </div>
                        ))}
                      </Card>}
                      {workflow.lab_orders?.length>0 && <Card title="Lab Orders">
                        {workflow.lab_orders.map((l:any,i:number)=>(
                          <div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:8,borderBottom:'1px solid #f3f4f6'}}>
                            <span>{l.test}</span>
                            <Badge variant={l.urgency==='stat'?'error':l.urgency==='urgent'?'warning':'info'}>{l.urgency}</Badge>
                          </div>
                        ))}
                      </Card>}
                      {workflow.referrals?.length>0 && <Card title="Referrals">
                        {workflow.referrals.map((r:any,i:number)=>(
                          <div key={i} style={{padding:8,borderBottom:'1px solid #f3f4f6'}}>
                            <strong>{r.specialty}</strong> <Badge variant="warning">{r.urgency}</Badge>
                            <div style={{fontSize:12,color:'#6b7280'}}>{r.rationale}</div>
                          </div>
                        ))}
                      </Card>}
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <style>{`@keyframes pulse{0%,100%{opacity:1}50%{opacity:0.3}}@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );
}

function EditableSec({label,value,onChange}:{label:string;value:string;onChange:(v:string)=>void}) {
  return (
    <div>
      <h4 style={{fontSize:13,fontWeight:600,color:'#1d4ed8',marginBottom:4}}>{label}</h4>
      <textarea value={value} onChange={e=>onChange(e.target.value)} rows={3}
        style={{width:'100%',padding:8,fontSize:13,border:'1px solid #d1d5db',borderRadius:6,fontFamily:'inherit',resize:'vertical',background:'#fff'}} />
    </div>
  );
}

const el = document.getElementById('encounter-root');
if (el) {
  const demoNo = el.dataset.demoNo || '';
  const demoName = el.dataset.demoName || '';
  if (demoNo) el.setAttribute('data-loaded', 'true');
  createRoot(el).render(<EncounterWorkspace />);
}
